     1→import { PrecisionClock } from '@psyforge/timing';
     2→import { Task, TaskState } from './Task.js';
     3→import { TaskPriority, TaskPriorityUtils } from './TaskPriority.js';
     4→import { Timeline } from './Timeline.js';
     5→
     6→/**
     7→ * Scheduled task entry with timing information
     8→ */
     9→interface ScheduledTask {
    10→  task: Task;
    11→  scheduledTime: number;
    12→  frameNumber: number;
    13→  timeline?: Timeline;
    14→}
    15→
    16→/**
    17→ * Scheduler performance metrics
    18→ */
    19→export interface SchedulerMetrics {
    20→  /** Number of tasks executed */
    21→  tasksExecuted: number;
    22→  /** Number of tasks that executed late */
    23→  lateExecutions: number;
    24→  /** Average timing error in milliseconds */
    25→  averageTimingError: number;
    26→  /** Maximum timing error observed */
    27→  maxTimingError: number;
    28→  /** Current queue length */
    29→  queueLength: number;
    30→  /** Frame rate (tasks per second) */
    31→  frameRate: number;
    32→  /** CPU usage estimate (0-1) */
    33→  cpuUsage: number;
    34→}
    35→
    36→/**
    37→ * Scheduler configuration options
    38→ */
    39→export interface SchedulerOptions {
    40→  /** Maximum tasks to execute per frame */
    41→  maxTasksPerFrame?: number;
    42→  /** Maximum frame time budget in milliseconds */
    43→  frameTimeBudget?: number;
    44→  /** Whether to use high-precision timing */
    45→  useHighPrecisionTiming?: boolean;
    46→  /** Timing error tolerance in milliseconds */
    47→  timingTolerance?: number;
    48→  /** Whether to preempt lower priority tasks */
    49→  allowPreemption?: boolean;
    50→}
    51→
    52→/**
    53→ * Hierarchical task scheduler with precise timing control
    54→ * Manages experiment execution with sub-millisecond timing accuracy
    55→ */
    56→export class Scheduler {
    57→  private readonly _clock: PrecisionClock;
    58→  private readonly _options: Required<SchedulerOptions>;
    59→  
    60→  private _taskQueue: ScheduledTask[] = [];
    61→  private _runningTasks: Set<Task> = new Set();
    62→  private _timelines: Set<Timeline> = new Set();
    63→  private _isRunning: boolean = false;
    64→  private _frameHandle: number | null = null;
    65→  private _frameNumber: number = 0;
    66→  
    67→  // Performance tracking
    68→  private _metrics: SchedulerMetrics = {
    69→    tasksExecuted: 0,
    70→    lateExecutions: 0,
    71→    averageTimingError: 0,
    72→    maxTimingError: 0,
    73→    queueLength: 0,
    74→    frameRate: 0,
    75→    cpuUsage: 0
    76→  };
    77→  private _timingErrors: number[] = [];
    78→  private _frameStartTime: number = 0;
    79→
    80→  constructor(options: SchedulerOptions = {}) {
    81→    this._options = {
    82→      maxTasksPerFrame: options.maxTasksPerFrame ?? 10,
    83→      frameTimeBudget: options.frameTimeBudget ?? 8, // 8ms for 120fps headroom
    84→      useHighPrecisionTiming: options.useHighPrecisionTiming ?? true,
    85→      timingTolerance: options.timingTolerance ?? 2, // 2ms tolerance
    86→      allowPreemption: options.allowPreemption ?? true
    87→    };
    88→
    89→    this._clock = new PrecisionClock();
    90→  }
    91→
    92→  /**
    93→   * Current scheduler metrics
    94→   */
    95→  get metrics(): Readonly<SchedulerMetrics> {
    96→    return { ...this._metrics };
    97→  }
    98→
    99→  /**
   100→   * Whether scheduler is running
   101→   */
   102→  get isRunning(): boolean {
   103→    return this._isRunning;
   104→  }
   105→
   106→  /**
   107→   * Number of tasks in queue
   108→   */
   109→  get queueLength(): number {
   110→    return this._taskQueue.length;
   111→  }
   112→
   113→  /**
   114→   * Number of currently running tasks
   115→   */
   116→  get runningTaskCount(): number {
   117→    return this._runningTasks.size;
   118→  }
   119→
   120→  /**
   121→   * Start the scheduler
   122→   */
   123→  start(): void {
   124→    if (this._isRunning) return;
   125→
   126→    this._isRunning = true;
   127→    this._frameNumber = 0;
   128→    this._scheduleNextFrame();
   129→  }
   130→
   131→  /**
   132→   * Stop the scheduler
   133→   */
   134→  stop(): void {
   135→    if (!this._isRunning) return;
   136→
   137→    this._isRunning = false;
   138→    
   139→    if (this._frameHandle !== null) {
   140→      cancelAnimationFrame(this._frameHandle);
   141→      this._frameHandle = null;
   142→    }
   143→
   144→    // Cancel all running tasks
   145→    for (const task of this._runningTasks) {
   146→      task.cancel(new Error('Scheduler stopped'));
   147→    }
   148→    this._runningTasks.clear();
   149→
   150→    // Stop all timelines
   151→    for (const timeline of this._timelines) {
   152→      if (timeline.isRunning) {
   153→        timeline.stop();
   154→      }
   155→    }
   156→  }
   157→
   158→  /**
   159→   * Schedule a task to execute at a specific time
   160→   */
   161→  scheduleTask(task: Task, executeAt: number): void {
   162→    if (!this._isRunning) {
   163→      throw new Error('Scheduler is not running');
   164→    }
   165→
   166→    const scheduledTask: ScheduledTask = {
   167→      task,
   168→      scheduledTime: executeAt,
   169→      frameNumber: this._frameNumber
   170→    };
   171→
   172→    this._insertTaskByPriority(scheduledTask);
   173→    this._metrics.queueLength = this._taskQueue.length;
   174→  }
   175→
   176→  /**
   177→   * Schedule a task to execute after a delay
   178→   */
   179→  scheduleDelayed(task: Task, delayMs: number): void {
   180→    const executeAt = this._clock.now().monotonic + delayMs;
   181→    this.scheduleTask(task, executeAt);
   182→  }
   183→
   184→  /**
   185→   * Schedule a task to execute on the next frame
   186→   */
   187→  scheduleNextFrame(task: Task): void {
   188→    const nextFrameTime = this._clock.now().monotonic + 16.67; // ~60fps
   189→    this.scheduleTask(task, nextFrameTime);
   190→  }
   191→
   192→  /**
   193→   * Add a timeline to be managed by the scheduler
   194→   */
   195→  addTimeline(timeline: Timeline): void {
   196→    this._timelines.add(timeline);
   197→
   198→    // Schedule timeline start
   199→    const startTask = new Task(`Start ${timeline.name}`, async () => {
   200→      await timeline.start();
   201→    }, { priority: TaskPriority.HIGH });
   202→
   203→    this.scheduleNextFrame(startTask);
   204→  }
   205→
   206→  /**
   207→   * Remove a timeline from scheduler management
   208→   */
   209→  removeTimeline(timeline: Timeline): void {
   210→    this._timelines.delete(timeline);
   211→    
   212→    if (timeline.isRunning) {
   213→      timeline.stop();
   214→    }
   215→  }
   216→
   217→  /**
   218→   * Cancel a specific task
   219→   */
   220→  cancelTask(task: Task): boolean {
   221→    // Remove from queue
   222→    const queueIndex = this._taskQueue.findIndex(st => st.task === task);
   223→    if (queueIndex !== -1) {
   224→      this._taskQueue.splice(queueIndex, 1);
   225→      task.cancel(new Error('Task cancelled by scheduler'));
   226→      this._metrics.queueLength = this._taskQueue.length;
   227→      return true;
   228→    }
   229→
   230→    // Cancel if running
   231→    if (this._runningTasks.has(task)) {
   232→      task.cancel(new Error('Task cancelled by scheduler'));
   233→      this._runningTasks.delete(task);
   234→      return true;
   235→    }
   236→
   237→    return false;
   238→  }
   239→
   240→  /**
   241→   * Clear all pending tasks
